using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    // ───────────────────────────────────────────────
    //  CalculateTotal – DataRow (compile-time data)
    // ───────────────────────────────────────────────

    [TestMethod]
    [DataRow(10.00, 1, 0.0,  10.00,  DisplayName = "Single item, no tax")]
    [DataRow(10.00, 2, 0.0,  20.00,  DisplayName = "Two items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00,  DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62,  DisplayName = "Fractional price, 8% tax")]
    [DataRow(0.00,  5, 0.10, 0.00,   DisplayName = "Zero unit price")]
    [DataRow(10.00, 0, 0.10, 0.00,   DisplayName = "Zero quantity")]
    [DataRow(99.99, 1, 1.0,  199.98, DisplayName = "Max tax rate (100%)")]
    public void CalculateTotal_ValidInputs_ReturnsExpected(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    // ───────────────────────────────────────────────
    //  CalculateTotal – invalid inputs
    // ───────────────────────────────────────────────

    [TestMethod]
    [DataRow(-1.0, 1, 0.10, DisplayName = "Negative unit price")]
    [DataRow(10.0, -1, 0.10, DisplayName = "Negative quantity")]
    [DataRow(10.0, 1, -0.1,  DisplayName = "Negative tax rate")]
    [DataRow(10.0, 1, 1.5,   DisplayName = "Tax rate > 1")]
    public void CalculateTotal_InvalidInputs_ThrowsArgumentOutOfRange(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    // ───────────────────────────────────────────────
    //  ApplyDiscount – DynamicData (runtime data)
    // ───────────────────────────────────────────────

    public static IEnumerable<object[]> DiscountTestCases
    {
        get
        {
            yield return [100m, 0m, 100m, "No discount"];
            yield return [100m, 10m, 90m, "10% off"];
            yield return [100m, 50m, 50m, "50% off"];
            yield return [100m, 100m, 0m, "100% off (free)"];
            yield return [59.99m, 25m, 44.9925m, "Fractional price, 25% off"];
            yield return [0m, 50m, 0m, "Zero price, 50% off"];
        }
    }

    [TestMethod]
    [DynamicData(nameof(DiscountTestCases), DynamicDataSourceType.Property,
        DynamicDataDisplayName = nameof(GetDiscountDisplayName))]
    public void ApplyDiscount_ValidInputs_ReturnsExpected(
        decimal price, decimal discountPercent, decimal expected, string _)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result);
    }

    public static string GetDiscountDisplayName(MethodInfo _, object[] data) => (string)data[3];

    // ───────────────────────────────────────────────
    //  ApplyDiscount – invalid discount percentages
    // ───────────────────────────────────────────────

    [TestMethod]
    [DataRow(-1.0,  DisplayName = "Negative discount")]
    [DataRow(100.1, DisplayName = "Discount > 100%")]
    public void ApplyDiscount_InvalidPercent_ThrowsArgumentOutOfRange(double discountPercent)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(100m, (decimal)discountPercent));
    }

    // ───────────────────────────────────────────────
    //  FormatPrice – DynamicData from method source
    // ───────────────────────────────────────────────

    public static IEnumerable<object[]> FormatPriceCases()
    {
        yield return [19.99m, "$", "$19.99"];
        yield return [19.99m, "€", "€19.99"];
        yield return [1000m, "$", "$1000.00"];
        yield return [0.5m, "£", "£0.50"];
    }

    [TestMethod]
    [DynamicData(nameof(FormatPriceCases), DynamicDataSourceType.Method)]
    public void FormatPrice_ReturnsCurrencyFormattedString(
        decimal price, string symbol, string expected)
    {
        var result = _calculator.FormatPrice(price, symbol);

        Assert.AreEqual(expected, result);
    }
}

